const r = $input.first().json.report || {};
const log = r.activity_log || [];
const events = r.security_events || [];
const sevColor = { critical: '#7f1d1d', high: '#dc2626', medium: '#ea580c', low: '#f59e0b', info: '#6b7280' };
const statusColor = s => s==='error' ? '#dc2626' : (s==='success' ? '#10b981' : '#6b7280');
const row = (cells) => '<tr>'+cells.map(c=>'<td style="padding:6px 8px;border-bottom:1px solid #eee;font-size:12px;vertical-align:top">'+c+'</td>').join('')+'</tr>';
const tbl = (headers, rows) => '<table style="width:100%;background:white;border-collapse:collapse;border-radius:6px;overflow:hidden"><thead style="background:#1f2937;color:white"><tr>'+headers.map(h=>'<th style="padding:8px;text-align:left;font-size:11px">'+h+'</th>').join('')+'</tr></thead><tbody>'+(rows.length>0?rows.join(''):row(headers.map(()=>'<i style="color:#10b981">sin actividad</i>')))+'</tbody></table>';
const logRows = log.map(l=>row([
  new Date(l.created_at).toISOString().slice(11,16),
  '<b>'+(l.agent_name||'?')+'</b>',
  '<code>'+l.action+'</code>',
  '<span style="color:'+statusColor(l.status)+'">'+(l.status||'-')+'</span>',
  l.preview||'-'
]));
const eventRows = events.map(e=>row([
  new Date(e.occurred_at).toISOString().slice(11,16),
  '<span style="background:'+(sevColor[e.severity]||'#6b7280')+';color:white;padding:1px 6px;border-radius:3px;font-size:10px">'+(e.severity||'?').toUpperCase()+'</span>',
  e.event_type,
  e.source_ip||'-',
  e.resolved ? '<span style="color:#10b981">resolved</span>' : '<span style="color:#dc2626">UNRESOLVED</span>',
  e.preview||'-'
]));
const html = '<!DOCTYPE html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Actividad reciente — ArquitAI</title>' +
'<style>body{font-family:-apple-system,Arial,sans-serif;max-width:1100px;margin:24px auto;padding:16px;color:#1f2937;background:#f3f4f6}h1{color:#0f172a;margin:0 0 4px}h2{color:#374151;font-size:15px;margin:24px 0 8px}.meta{color:#64748b;font-size:13px}.errors{background:#fee2e2;color:#991b1b;padding:10px;border-radius:6px;font-size:13px}</style>' +
'</head><body>' +
'<a href="/webhook/admin-index" style="color:#2563eb;font-size:13px;text-decoration:none">← Admin index</a>' +
'<h1>Actividad reciente</h1>' +
'<div class="meta">Ventana de 48h — ' + new Date().toLocaleString('es-ES') + '</div>' +
((r.workflow_errors_24h||0) > 0 ? '<div class="errors" style="margin:12px 0"><b>'+r.workflow_errors_24h+' errores de workflow en 24h</b> — ver tabla activity_log</div>' : '') +
'<h2>Security events 48h ('+events.length+')</h2>' +
 tbl(['Hora','Sev','Tipo','IP','Status','Descripcion'], eventRows) +
'<h2>Activity log 48h, top 50 ('+log.length+')</h2>' +
 tbl(['Hora','Agent','Action','Status','Preview'], logRows) +
'<p style="color:#94a3b8;font-size:11px;margin-top:32px;text-align:center">Para historico mas alla de 48h: consulta SQL directa.</p>' +
'</body></html>';
return [{ json: { html } }];
